from python_pipeline.utils.schema.chunk_schema import *
from python_pipeline.utils.schema.shared_schema import *

def chunk_to_vector_text(chunk) -> str:
    """Convert ChunkSummary to embedding-optimized string"""
    parts = []

    parts.append(f"Function: {chunk.function_info.function_name}")
    parts.append(f"File: {chunk.function_info.filename}")
    parts.append(f"Path: {chunk.function_info.filepath}")

    if chunk.parameters:
        params = ", ".join([f"{p.name} ({p.type}): {p.description}" for p in chunk.parameters])
        parts.append(f"Parameters: {params}")

    parts.append(f"Returns: {chunk.return_value}")
    parts.append(f"Logic: {chunk.logic_summary}")

    if chunk.dependencies:
        parts.append(f"Dependencies: {', '.join(chunk.dependencies)}")

    if chunk.side_effects and chunk.side_effects != "NONE":
        parts.append(f"Side Effects: {chunk.side_effects}")

    if chunk.error_handling and chunk.error_handling != "NONE":
        parts.append(f"Error Handling: {chunk.error_handling}")

    parts.append(f"Complexity: {chunk.complexity}")

    if chunk.class_purpose:
        parts.append(f"Class Purpose: {chunk.class_purpose}")

    if chunk.attributes:
        attrs = ", ".join([f"{a.name} ({a.type}): {a.description}" for a in chunk.attributes])
        parts.append(f"Attributes: {attrs}")

    if chunk.methods_overview:
        methods = ", ".join([m.name for m in chunk.methods_overview])
        parts.append(f"Methods: {methods}")

    if chunk.inheritance:
        parts.append(f"Inherits: {chunk.inheritance}")

    if chunk.tags:
        parts.append(f"Tags: {', '.join(chunk.tags)}")

    return " | ".join(parts)


def file_to_vector_text(file_summary) -> str:
    """Convert FileLevelSummary to embedding-optimized string"""
    parts = []

    parts.append(f"File: {file_summary.filename}")
    parts.append(f"Path: {file_summary.filepath}")
    parts.append(f"Module: {file_summary.module_name}")
    parts.append(f"Purpose: {file_summary.file_purpose}")
    parts.append(f"Role: {file_summary.architecture_role}")
    parts.append(f"Logic Flow: {file_summary.core_logic_flow}")

    if file_summary.important_symbols:
        symbols = ", ".join([f"{s.symbol_id} ({s.role})" for s in file_summary.important_symbols])
        parts.append(f"Key Symbols: {symbols}")

    if file_summary.internal_dependencies:
        parts.append(f"Internal Dependencies: {', '.join(file_summary.internal_dependencies)}")

    if file_summary.external_dependencies:
        parts.append(f"External Dependencies: {', '.join(file_summary.external_dependencies)}")

    if file_summary.public_api:
        parts.append(f"Public API: {', '.join(file_summary.public_api)}")

    if file_summary.side_effects:
        parts.append(f"Side Effects: {', '.join(file_summary.side_effects)}")

    parts.append(f"Error Handling: {file_summary.error_handling_strategy}")

    if file_summary.state_management:
        parts.append(f"State Management: {file_summary.state_management}")

    if file_summary.security_considerations:
        parts.append(f"Security: {file_summary.security_considerations}")

    if file_summary.performance_notes:
        parts.append(f"Performance: {file_summary.performance_notes}")

    if file_summary.related_files:
        parts.append(f"Related Files: {', '.join(file_summary.related_files)}")

    parts.append(f"Complexity: {file_summary.overall_complexity}")
    parts.append(f"Tags: {', '.join(file_summary.tags)}")

    return " | ".join(parts)


